INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (0, 0, 1, 1, 10, 72033, 0, "そりゃそうですよね……\nいきなり前のめり過ぎ太郎でした……", 72, 1, 11);
